<span class="line"><span style="color:#F8F8F2;">        line </span><span style="color:#F92672;">=</span><span style="color:#F8F8F2;"> line.replace(</span><span style="color:#E6DB74;">&#39;“&#39;</span><span style="color:#F8F8F2;">, </span><span style="color:#E6DB74;">&#39;&#39;</span><span style="color:#F8F8F2;">)</span></span>
